-- PMP OPS — Seed data (run after schema + policies)
-- Uses sample jobs, presses, todos, progress_log, qc_log for demo.

-- Clear existing (optional; comment out if you want to preserve data)
-- TRUNCATE jobs, progress_log, presses, todos, qc_log RESTART IDENTITY CASCADE;

-- Jobs (id, catalog, artist, album, invoice, status, due, press, client, email, location, last_contact, format, vinyl_type, qty, weight, color, specialty, label_type, sleeve, jacket, outer, cpl, notes, assembly, inv_date, deposit, inv2, pay2, assets)
ON CONFLICT (id) DO UPDATE SET updated_at = now();

-- Presses
ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, type = EXCLUDED.type, status = EXCLUDED.status, job_id = EXCLUDED.job_id;

-- Todos (category, text, done, who, sort_order)
ON CONFLICT (id) DO UPDATE SET category = EXCLUDED.category, text = EXCLUDED.text, done = EXCLUDED.done, who = EXCLUDED.who, sort_order = EXCLUDED.sort_order;

